function mk(name, city, county, season, detail) {
  return `${name} is one of ${county}s most celebrated market traditions -- a beloved ${season} gathering in ${city} where vendors and visitors from across the region come together for a day of Swedish market culture at its finest.\n\n${detail}\n\nSweden's knallemarknad tradition has sustained community life for centuries, creating regular commercial and social gathering points that connect neighbours, support local commerce and maintain the cultural identity that makes Swedish towns and villages genuinely distinctive.\n\nFor vendors, ${name} delivers reliable access to a quality Swedish regional audience with strong community engagement, well-organised market infrastructure and the enthusiastic buyer participation that makes Swedish market events among the finest commercial settings in Scandinavia.`;
}

